-- CCN Council Prep Pro — practice question batch 4
-- 94 AI-generated labeled practice questions covering the two courses with
-- zero prior coverage (Applied Anatomy & Physiology CCN 410, Anaesthesia CCN 415),
-- paediatric-specific surgical/medical emergencies (CCN 422), and deeper coverage of
-- Radiology, ICT, Lab Sciences, Disaster Nursing, Ethics/Management, Pharmacology.
-- source='AI Practice Question' on every row.
-- Run this once in the Supabase SQL Editor (Project -> SQL Editor -> New query).

on conflict (id) do update set topic=excluded.topic, source=excluded.source, q=excluded.q, opts=excluded.opts, ans_idx=excluded.ans_idx, exp=excluded.exp, category=excluded.category, category_icon=excluded.category_icon, is_active=true;