insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(3208, 'Applied Anatomy & Physiology (CCN 410) — Respiratory', 'AI Practice Question', 'Gaseous exchange in the lungs occurs primarily at the level of the:', '["Trachea", "Bronchi", "Alveoli", "Larynx"]'::jsonb, 2, 'The alveoli, with their thin walls and rich capillary network, are the site of gas exchange between air and blood.', 'Anatomy & Physiology', '🧬', true),
(3209, 'Applied Anatomy & Physiology (CCN 410) — Respiratory', 'AI Practice Question', 'Which factor does NOT directly affect the rate or depth of respiration?', '["Blood CO2 levels", "Blood pH", "Blood glucose level", "Blood O2 levels"]'::jsonb, 2, 'Respiration is primarily regulated by chemoreceptors sensing CO2, pH and O2 levels — blood glucose has no direct regulatory role in respiratory drive.', 'Anatomy & Physiology', '🧬', true),
(3210, 'Applied Anatomy & Physiology (CCN 410) — Respiratory', 'AI Practice Question', 'Total lung capacity is best defined as:', '["The volume of air moved in a single normal breath", "The maximum volume of air the lungs can hold after maximal inspiration", "The volume remaining in the lungs after maximal expiration", "The volume exhaled in the first second of forced expiration"]'::jsonb, 1, 'Total lung capacity is the maximum volume of air the lungs can contain after a maximal inspiratory effort.', 'Anatomy & Physiology', '🧬', true),
(3211, 'Applied Anatomy & Physiology (CCN 410) — Respiratory', 'AI Practice Question', 'Residual volume is the amount of air:', '["Inhaled during a normal breath", "Exhaled forcefully after normal expiration", "Remaining in the lungs after maximal expiration", "Inhaled during maximal inspiration beyond tidal volume"]'::jsonb, 2, 'Residual volume is the air that remains in the lungs even after the most forceful expiration, preventing lung collapse.', 'Anatomy & Physiology', '🧬', true),
(3212, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'The primary function of red blood cells is to:', '["Fight infection", "Transport oxygen and carbon dioxide", "Form blood clots", "Produce antibodies"]'::jsonb, 1, 'Red blood cells, via haemoglobin, transport oxygen from the lungs to tissues and help carry carbon dioxide back to the lungs.', 'Anatomy & Physiology', '🧬', true),
(3213, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'Before administering a blood transfusion, blood grouping and cross-matching is essential mainly to:', '["Determine the patient''s cholesterol level", "Prevent a haemolytic transfusion reaction from incompatible blood", "Measure clotting time", "Assess kidney function"]'::jsonb, 1, 'Grouping and cross-matching confirms ABO/Rh compatibility between donor and recipient, preventing a potentially fatal haemolytic transfusion reaction.', 'Anatomy & Physiology', '🧬', true),
(3214, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'Platelets (thrombocytes) primarily function in:', '["Oxygen transport", "Blood clotting/haemostasis", "Fighting bacterial infection", "Producing hormones"]'::jsonb, 1, 'Platelets are essential for haemostasis, aggregating at sites of vessel injury to help form a clot.', 'Anatomy & Physiology', '🧬', true),
(3215, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'The lymphatic system''s primary functions include all of the following EXCEPT:', '["Draining excess interstitial fluid back into the bloodstream", "Transporting absorbed dietary fats from the intestine", "Supporting immune function", "Directly pumping oxygenated blood to tissues"]'::jsonb, 3, 'Pumping oxygenated blood to tissues is the role of the cardiovascular system''s heart, not the lymphatic system, which drains fluid, transports fats, and supports immunity.', 'Anatomy & Physiology', '🧬', true),
(3216, 'Applied Anatomy & Physiology (CCN 410) — Renal', 'AI Practice Question', 'The functional unit of the kidney responsible for filtration is the:', '["Renal pelvis", "Nephron", "Ureter", "Bladder trigone"]'::jsonb, 1, 'The nephron, comprising the glomerulus and its associated tubules, is the kidney''s basic functional/filtering unit.', 'Anatomy & Physiology', '🧬', true),
(3217, 'Applied Anatomy & Physiology (CCN 410) — Renal', 'AI Practice Question', 'The kidneys contribute to regulation of acid-base balance mainly by:', '["Producing insulin", "Excreting or reabsorbing hydrogen ions and bicarbonate", "Regulating heart rate", "Producing bile"]'::jsonb, 1, 'The kidneys help maintain acid-base balance by selectively excreting hydrogen ions and reabsorbing/regenerating bicarbonate.', 'Anatomy & Physiology', '🧬', true),
(3218, 'Applied Anatomy & Physiology (CCN 410) — Renal', 'AI Practice Question', 'The counter-current mechanism in the kidney is primarily involved in:', '["Producing red blood cells", "Concentrating or diluting urine to regulate body fluid balance", "Filtering large proteins out of the blood", "Regulating blood pH exclusively via the lungs"]'::jsonb, 1, 'The counter-current multiplier/exchange system in the loop of Henle and vasa recta allows the kidney to concentrate or dilute urine, regulating body water balance.', 'Anatomy & Physiology', '🧬', true),
(3219, 'Applied Anatomy & Physiology (CCN 410) — Integumentary & GIT', 'AI Practice Question', 'The skin''s appendages include all of the following EXCEPT:', '["Hair follicles", "Sweat glands", "Sebaceous glands", "Alveoli"]'::jsonb, 3, 'Alveoli are part of the respiratory system, not skin appendages — hair follicles, sweat glands and sebaceous glands are all skin appendages.', 'Anatomy & Physiology', '🧬', true),
(3220, 'Applied Anatomy & Physiology (CCN 410) — Integumentary & GIT', 'AI Practice Question', 'Which gastrointestinal process refers to the physical and chemical breakdown of food into absorbable units?', '["Absorption", "Digestion", "Transportation", "Excretion"]'::jsonb, 1, 'Digestion is the breakdown of food (mechanically and chemically) into smaller, absorbable molecules.', 'Anatomy & Physiology', '🧬', true),
(3221, 'Applied Anatomy & Physiology (CCN 410) — Integumentary & GIT', 'AI Practice Question', 'Absorption of digested nutrients occurs primarily in the:', '["Stomach", "Oesophagus", "Small intestine", "Large intestine"]'::jsonb, 2, 'The small intestine, with its large surface area from villi and microvilli, is the primary site of nutrient absorption.', 'Anatomy & Physiology', '🧬', true),
(3222, 'Applied Anatomy & Physiology (CCN 410) — Integumentary & GIT', 'AI Practice Question', 'Gastrointestinal glandular secretions primarily aid in:', '["Chemical breakdown of food and enzymatic digestion", "Producing red blood cells", "Regulating body temperature exclusively", "Filtering blood"]'::jsonb, 0, 'GI glands (salivary, gastric, pancreatic, liver/bile) secrete enzymes and other substances essential for chemically breaking down food.', 'Anatomy & Physiology', '🧬', true),
(3223, 'Applied Anatomy & Physiology (CCN 410) — Central Nervous System', 'AI Practice Question', 'The spinal cord''s reflex action allows for:', '["Conscious decision-making before every movement", "A rapid, automatic response to a stimulus, bypassing the need for the brain to process it first", "Only sensory perception with no motor output", "Hormone regulation"]'::jsonb, 1, 'Spinal reflexes allow rapid, automatic responses (e.g. withdrawing a hand from a hot surface) via a reflex arc, without requiring conscious brain processing first.', 'Anatomy & Physiology', '🧬', true),
(3224, 'Applied Anatomy & Physiology (CCN 410) — Central Nervous System', 'AI Practice Question', 'Cranial nerves originate directly from the:', '["Spinal cord only", "Brain and brainstem", "Peripheral muscles", "Autonomic ganglia only"]'::jsonb, 1, 'The 12 pairs of cranial nerves arise directly from the brain and brainstem, unlike spinal nerves which arise from the spinal cord.', 'Anatomy & Physiology', '🧬', true),
(3225, 'Applied Anatomy & Physiology (CCN 410) — Central Nervous System', 'AI Practice Question', 'During embryological development, nervous tissue organisation ultimately gives rise to the:', '["Cardiovascular system only", "Central and peripheral nervous systems", "Skeletal system exclusively", "Endocrine system exclusively"]'::jsonb, 1, 'Nervous tissue development and organisation gives rise to both the central (brain, spinal cord) and peripheral nervous systems.', 'Anatomy & Physiology', '🧬', true),
(3226, 'Applied Anatomy & Physiology (CCN 410) — Endocrine', 'AI Practice Question', 'Endocrine glands differ from exocrine glands in that endocrine glands:', '["Secrete hormones directly into the bloodstream, with no ducts", "Always secrete through a duct onto an epithelial surface", "Never produce chemical messengers", "Only function during childhood"]'::jsonb, 0, 'Endocrine glands are ductless — they release hormones directly into the bloodstream, unlike exocrine glands which secrete via ducts.', 'Anatomy & Physiology', '🧬', true),
(3227, 'Applied Anatomy & Physiology (CCN 410) — Endocrine', 'AI Practice Question', 'Hormonal control of a target organ commonly occurs through:', '["Direct nerve stimulation only, with no chemical signal", "Hormones binding to specific receptors on or in target cells", "Physical contact between glands and organs", "Muscle contraction alone"]'::jsonb, 1, 'Hormones exert their effects by binding to specific receptors on or within target cells, triggering a physiological response.', 'Anatomy & Physiology', '🧬', true),
(3228, 'Applied Anatomy & Physiology (CCN 410) — Endocrine', 'AI Practice Question', 'Negative feedback, as a mechanism of hormonal control, means that:', '["Rising hormone levels stimulate even more hormone release, with no limit", "Rising hormone/product levels suppress further release, keeping levels in a stable range", "Hormone levels are entirely independent of blood concentration", "Feedback only applies to the nervous system, never hormones"]'::jsonb, 1, 'Negative feedback is the most common hormonal regulation mechanism: rising levels of a hormone or its effect suppress further release, maintaining homeostasis.', 'Anatomy & Physiology', '🧬', true),
(3229, 'Applied Anatomy & Physiology (CCN 410) — Respiratory', 'AI Practice Question', 'Which structure connects the pharynx to the bronchi, serving as the main airway?', '["Oesophagus", "Trachea", "Aorta", "Ureter"]'::jsonb, 1, 'The trachea is the main airway connecting the larynx/pharynx above to the bronchi below, allowing air to pass to and from the lungs.', 'Anatomy & Physiology', '🧬', true),
(3230, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'Clotting factors are primarily synthesised by the:', '["Kidneys", "Liver", "Spleen", "Pancreas"]'::jsonb, 1, 'Most clotting factors are synthesised in the liver, which is why liver disease can impair coagulation.', 'Anatomy & Physiology', '🧬', true),
(3231, 'Applied Anatomy & Physiology (CCN 410) — Renal', 'AI Practice Question', 'The urinary bladder''s primary anatomical function is to:', '["Filter blood", "Store urine until voiding", "Produce urine", "Reabsorb electrolytes"]'::jsonb, 1, 'The bladder is a muscular reservoir that stores urine produced by the kidneys until it is voided through the urethra.', 'Anatomy & Physiology', '🧬', true),
(3232, 'Applied Anatomy & Physiology (CCN 410) — Cardiovascular', 'AI Practice Question', 'The heart''s four chambers consist of:', '["Two atria and two ventricles", "Four ventricles only", "Four atria only", "One atrium and three ventricles"]'::jsonb, 0, 'The heart has two upper chambers (right and left atria) and two lower chambers (right and left ventricles).', 'Anatomy & Physiology', '🧬', true),
(3233, 'Applied Anatomy & Physiology (CCN 410) — Central Nervous System', 'AI Practice Question', 'The brain structure primarily responsible for coordinating balance and fine motor movement is the:', '["Cerebrum", "Cerebellum", "Medulla oblongata", "Thalamus"]'::jsonb, 1, 'The cerebellum coordinates balance, posture, and the fine-tuning of voluntary motor movements.', 'Anatomy & Physiology', '🧬', true),
(3234, 'Applied Anatomy & Physiology (CCN 410) — Renal', 'AI Practice Question', 'The glomerulus within the nephron is primarily responsible for:', '["Reabsorbing all filtered water", "Filtering blood to form the initial filtrate", "Secreting hormones only", "Storing urine"]'::jsonb, 1, 'The glomerulus is a capillary tuft where blood is filtered under pressure, forming the initial filtrate that continues through the nephron''s tubules.', 'Anatomy & Physiology', '🧬', true),
(3235, 'Anaesthesia (CCN 415) — Ventilators', 'AI Practice Question', 'Before caring for a patient on a mechanical ventilator, the nurse should be familiar with all of the following EXCEPT:', '["The ventilator mode and settings in use", "Alarm limits and troubleshooting", "The patient''s dietary preferences prior to admission", "Signs of a blocked or displaced endotracheal tube"]'::jsonb, 2, 'Ventilator type, settings, alarms and airway complication recognition are essential nursing knowledge; pre-admission dietary preference has no bearing on safe ventilator care.', 'Anaesthesia & Perioperative Care', '💉', true),
(3236, 'Anaesthesia (CCN 415) — Ventilators', 'AI Practice Question', 'A sudden rise in peak airway pressure with a ventilated patient should immediately prompt the nurse to check for:', '["Low fluid intake", "A blocked or kinked endotracheal tube, or bronchospasm/secretions", "The patient''s temperature only", "The IV infusion rate"]'::jsonb, 0, 'A sudden peak pressure rise suggests an airway/circuit problem — blocked/kinked tube, bronchospasm, secretions, or pneumothorax — requiring prompt assessment.', 'Anaesthesia & Perioperative Care', '💉', true),
(3237, 'Anaesthesia (CCN 415) — Ventilators', 'AI Practice Question', 'Weaning a patient from mechanical ventilation is typically guided by:', '["A fixed calendar date regardless of clinical status", "Readiness criteria such as adequate oxygenation, haemodynamic stability, and ability to protect the airway", "The patient''s personal preference alone", "Random selection"]'::jsonb, 1, 'Weaning readiness is assessed against objective criteria — oxygenation, haemodynamic stability, mental status and airway protective reflexes — not arbitrary timing.', 'Anaesthesia & Perioperative Care', '💉', true),
(3238, 'Anaesthesia (CCN 415) — Ventilators', 'AI Practice Question', 'A recognised risk of prolonged mechanical ventilation is:', '["Improved spontaneous respiratory drive over time", "Ventilator-associated pneumonia (VAP)", "Guaranteed prevention of atelectasis", "Elimination of the need for sedation"]'::jsonb, 1, 'Prolonged mechanical ventilation increases the risk of ventilator-associated pneumonia, among other complications like barotrauma and diaphragmatic weakness.', 'Anaesthesia & Perioperative Care', '💉', true),
(3239, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Inhalational anaesthetic agents primarily produce their effect by acting on the:', '["Peripheral nervous system only", "Central nervous system, mainly via GABA-A enhancement and NMDA inhibition", "Cardiovascular system exclusively", "Renal system exclusively"]'::jsonb, 1, 'Volatile/gaseous anaesthetics act mainly on the CNS through enhancing inhibitory GABA-A transmission and inhibiting excitatory NMDA transmission.', 'Anaesthesia & Perioperative Care', '💉', true),
(3240, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Hypercarbia during anaesthesia refers to:', '["Elevated blood carbon dioxide levels", "Low blood oxygen levels", "Elevated blood glucose", "Low blood pressure"]'::jsonb, 0, 'Hypercarbia is an abnormally elevated level of carbon dioxide in the blood, a recognised risk during inadequately monitored anaesthesia/ventilation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3241, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Hypoxia during general anaesthesia refers to:', '["Inadequate oxygen delivery to tissues", "Excess oxygen delivery to tissues", "Elevated body temperature", "Low blood glucose"]'::jsonb, 0, 'Hypoxia is inadequate tissue oxygenation, a critical complication to detect and correct promptly during anaesthesia.', 'Anaesthesia & Perioperative Care', '💉', true),
(3242, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Central venous pressure (CVP) measurement during anaesthesia primarily provides information about:', '["Arterial oxygen saturation", "Right heart filling pressure/venous return, useful for guiding fluid management", "Airway resistance", "Blood glucose level"]'::jsonb, 1, 'CVP reflects right atrial/venous filling pressure and is used to help guide fluid administration and assess volume status.', 'Anaesthesia & Perioperative Care', '💉', true),
(3243, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Ventilation-perfusion (V/Q) mismatch during anaesthesia can result in:', '["Improved gas exchange", "Impaired oxygenation despite adequate ventilator settings", "No clinical effect", "Only affecting blood pressure, not oxygenation"]'::jsonb, 1, 'A mismatch between ventilated alveoli and perfused capillaries impairs effective gas exchange, contributing to hypoxaemia even with seemingly adequate ventilation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3244, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Indications for intubation in the critical care unit include all of the following EXCEPT:', '["Airway protection in a patient with reduced consciousness", "Respiratory failure requiring mechanical ventilation", "Anticipated airway compromise (e.g. severe burns/oedema)", "Mild, well-controlled hypertension"]'::jsonb, 3, 'Mild, well-controlled hypertension is not an indication for intubation — airway protection, respiratory failure, and anticipated airway compromise are recognised indications.', 'Anaesthesia & Perioperative Care', '💉', true),
(3245, 'Anaesthesia (CCN 415) — Post-Operative Care', 'AI Practice Question', 'Induced hypothermia used therapeutically in select critically ill patients is primarily intended to:', '["Increase metabolic rate", "Reduce cellular metabolic demand and provide organ protection (e.g. neuroprotection after cardiac arrest)", "Speed recovery from anaesthesia", "Increase oxygen consumption"]'::jsonb, 1, 'Therapeutic/induced hypothermia lowers metabolic demand and is used for organ protection, notably neuroprotection following cardiac arrest.', 'Anaesthesia & Perioperative Care', '💉', true),
(3246, 'Anaesthesia (CCN 415) — Post-Operative Care', 'AI Practice Question', 'Unintended perioperative hypothermia is associated with which complication?', '["Improved wound healing", "Increased risk of surgical site infection and coagulopathy", "Reduced shivering", "No clinically significant effects"]'::jsonb, 1, 'Unintended hypothermia increases the risk of surgical site infection, impaired coagulation, and patient discomfort (shivering) — active warming is used to prevent it.', 'Anaesthesia & Perioperative Care', '💉', true),
(3247, 'Anaesthesia (CCN 415) — Post-Operative Care', 'AI Practice Question', 'The first-line drug for adult cardiac arrest, given every 3–5 minutes, is:', '["Amiodarone", "Adrenaline (epinephrine)", "Atropine", "Furosemide"]'::jsonb, 1, 'IV adrenaline 1mg every 3–5 minutes is the cornerstone drug therapy in adult cardiac arrest resuscitation.', 'Anaesthesia & Perioperative Care', '💉', true),
(3248, 'Anaesthesia (CCN 415) — Post-Operative Care', 'AI Practice Question', 'Early defibrillation in a shockable cardiac arrest rhythm is important because:', '["It has no effect on survival", "Survival chances decrease significantly with every minute of delay", "It should always be delayed until advanced life support arrives", "It is only effective after 30 minutes of CPR"]'::jsonb, 1, 'For shockable rhythms, survival probability drops substantially with each minute defibrillation is delayed, making early defibrillation a survival priority.', 'Anaesthesia & Perioperative Care', '💉', true),
(3249, 'Anaesthesia (CCN 415) — Pulmonary Complications', 'AI Practice Question', 'Mendelson''s Syndrome refers to:', '["A cardiac arrhythmia occurring during anaesthesia", "Chemical pneumonitis from aspiration of gastric contents during anaesthesia", "A type of anaesthetic overdose", "A skin reaction to anaesthetic gas"]'::jsonb, 1, 'Mendelson''s Syndrome is aspiration pneumonitis resulting from inhalation of acidic gastric contents, a recognised anaesthetic complication.', 'Anaesthesia & Perioperative Care', '💉', true),
(3250, 'Anaesthesia (CCN 415) — Pulmonary Complications', 'AI Practice Question', 'To reduce the risk of aspiration during induction of anaesthesia in an at-risk patient, the nurse/anaesthetist should ensure:', '["The patient has recently eaten a full meal", "Adequate fasting time has been observed and rapid sequence induction is used if indicated", "No airway equipment is prepared", "The patient is positioned flat on their back with no head elevation regardless of risk"]'::jsonb, 1, 'Adequate fasting and, where indicated, rapid sequence induction with cricoid pressure reduce aspiration risk in at-risk patients.', 'Anaesthesia & Perioperative Care', '💉', true),
(3251, 'Anaesthesia (CCN 415) — Pulmonary Complications', 'AI Practice Question', 'Oxygen therapy toxicity is most associated with:', '["Short-term, low-concentration oxygen use", "Prolonged exposure to high concentrations of oxygen", "Use of room air only", "Nebulised bronchodilator therapy"]'::jsonb, 1, 'Prolonged high-concentration oxygen therapy can cause oxygen toxicity, contributing to lung injury — hence the principle of using the lowest effective FiO2.', 'Anaesthesia & Perioperative Care', '💉', true),
(3252, 'Anaesthesia (CCN 415) — Pulmonary Complications', 'AI Practice Question', 'A patient recovering from anaesthesia after a lung transplant requires particular nursing vigilance for:', '["Signs of rejection and pulmonary infection", "Only cardiac monitoring, with no respiratory focus", "Skin integrity exclusively", "Bowel function exclusively"]'::jsonb, 0, 'Post-transplant patients need close monitoring for graft rejection and infection, alongside standard post-anaesthetic respiratory and haemodynamic care.', 'Anaesthesia & Perioperative Care', '💉', true),
(3253, 'Anaesthesia (CCN 415) — Complications of Anaesthesia', 'AI Practice Question', 'Brain death determination in a patient following a severe anaesthetic/anoxic event requires:', '["A single informal bedside check with no formal protocol", "Formal, protocolised clinical testing meeting strict legal/medical criteria", "Family consent as the sole determining factor", "No specific testing — clinical impression alone suffices"]'::jsonb, 1, 'Brain death is determined through rigorous, protocolised clinical criteria (and sometimes confirmatory testing), not informal impression, given its serious medico-legal implications.', 'Anaesthesia & Perioperative Care', '💉', true),
(3254, 'Anaesthesia (CCN 415) — Complications of Anaesthesia', 'AI Practice Question', 'Anaesthetic death investigations typically consider all of the following EXCEPT:', '["Adequacy of pre-anaesthetic assessment", "Appropriateness of drug selection and dosing", "Monitoring during the procedure", "The patient''s choice of hospital ward décor"]'::jsonb, 3, 'Ward décor is irrelevant to an anaesthetic death investigation — pre-assessment adequacy, drug management and intraoperative monitoring are the relevant factors reviewed.', 'Anaesthesia & Perioperative Care', '💉', true),
(3255, 'Anaesthesia (CCN 415) — Ventilators', 'AI Practice Question', 'SIMV, as a mode of mechanical ventilation, stands for and allows:', '["Synchronized Intermittent Mandatory Ventilation — combines mandatory breaths with the ability for the patient to breathe spontaneously between them", "Simple Immediate Manual Ventilation — a purely manual bag-valve technique", "Static Inspiratory Muscle Ventilation — used only for muscle training", "Single Inflation Manual Volume — a one-time inflation mode"]'::jsonb, 0, 'SIMV (Synchronized Intermittent Mandatory Ventilation) delivers a set number of mandatory breaths synchronised with patient effort, while allowing spontaneous breaths in between.', 'Anaesthesia & Perioperative Care', '💉', true),
(3256, 'Anaesthesia (CCN 415) — Anaesthetic Gases', 'AI Practice Question', 'Care of anaesthetic devices between uses should include:', '["No cleaning is necessary between patients", "Appropriate cleaning/disinfection or sterilisation per manufacturer and infection-control guidelines", "Only visual inspection, with no cleaning", "Storing devices wet to preserve seals"]'::jsonb, 1, 'Anaesthetic equipment must be properly cleaned, disinfected or sterilised between patients according to infection-control protocols to prevent cross-contamination.', 'Anaesthesia & Perioperative Care', '💉', true),
(3257, 'Anaesthesia (CCN 415) — Post-Operative Care', 'AI Practice Question', 'Fluid therapy in the post-anaesthetic period should be guided primarily by:', '["A single fixed rate for every patient regardless of condition", "The individual patient''s fluid losses, haemodynamic status, and clinical response", "The time of day only", "The colour of the surgical dressing"]'::jsonb, 1, 'Post-operative fluid therapy must be individualised, guided by ongoing losses, haemodynamic monitoring, and the patient''s overall clinical picture — not a one-size-fits-all rate.', 'Anaesthesia & Perioperative Care', '💉', true),
(3258, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Classic presenting features of appendicitis in a child include periumbilical pain migrating to which quadrant?', '["Right upper quadrant", "Left lower quadrant", "Right lower quadrant", "Left upper quadrant"]'::jsonb, 2, 'Appendicitis classically presents with pain that starts periumbilically and migrates to the right lower quadrant (McBurney''s point).', 'Obstetric & Neonatal', '🤱', true),
(3259, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Intussusception in infants classically presents with:', '["Painless abdominal distension only", "Episodic colicky abdominal pain, vomiting, and ''redcurrant jelly'' stools", "Chronic constipation with no acute symptoms", "A silent, asymptomatic abdominal mass"]'::jsonb, 1, 'Intussusception classically presents with episodic colicky pain, vomiting, and blood-stained ''redcurrant jelly'' stool as the bowel telescopes into itself.', 'Obstetric & Neonatal', '🤱', true),
(3260, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Pyloric stenosis in infants classically presents with:', '["Bilious vomiting from birth", "Projectile, non-bilious vomiting typically starting around 3–6 weeks of age", "Chronic diarrhoea", "Bloody stools with fever"]'::jsonb, 1, 'Hypertrophic pyloric stenosis classically causes projectile, non-bilious vomiting, usually presenting between 3–6 weeks of age.', 'Obstetric & Neonatal', '🤱', true),
(3261, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'An incarcerated inguinal hernia in an infant requires:', '["No urgent action, since it will resolve spontaneously", "Urgent medical assessment, as it risks bowel strangulation/ischaemia", "Only outpatient follow-up in a few months", "Treatment with laxatives"]'::jsonb, 1, 'An incarcerated hernia risks strangulation of the bowel with resulting ischaemia, making it a surgical emergency requiring urgent assessment.', 'Obstetric & Neonatal', '🤱', true),
(3262, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Hirschsprung''s disease is caused by:', '["Excess ganglion cells in the bowel wall", "Absence of ganglion cells in a segment of bowel, causing functional obstruction", "A viral infection of the colon", "An allergic reaction to milk protein"]'::jsonb, 1, 'Hirschsprung''s disease results from congenital absence of ganglion cells (aganglionosis) in a segment of bowel, preventing normal peristalsis and causing obstruction.', 'Obstetric & Neonatal', '🤱', true),
(3263, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Malrotation with volvulus in an infant is a surgical emergency mainly because it can cause:', '["Mild, self-limiting abdominal discomfort", "Bowel ischaemia from twisting of the mesentery, risking bowel necrosis", "Only skin rash", "Chronic mild constipation"]'::jsonb, 1, 'Volvulus twists the bowel and its mesentery, cutting off blood supply and risking rapid bowel ischaemia/necrosis if not surgically corrected urgently.', 'Obstetric & Neonatal', '🤱', true),
(3264, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Oesophageal atresia in a newborn classically presents with:', '["Normal feeding with no complications", "Excessive drooling, choking and coughing with feeding attempts", "Delayed passage of meconium only", "No respiratory symptoms at all"]'::jsonb, 1, 'Oesophageal atresia prevents the oesophagus from connecting normally to the stomach, causing drooling, choking and coughing when feeds are attempted.', 'Obstetric & Neonatal', '🤱', true),
(3265, 'Paediatric Surgical Emergencies (CCN 422)', 'AI Practice Question', 'Tracheo-oesophageal fistula is often associated with which other congenital anomaly?', '["Oesophageal atresia", "Cleft lip only", "Club foot only", "Polydactyly only"]'::jsonb, 0, 'Tracheo-oesophageal fistula commonly co-occurs with oesophageal atresia, and the combination requires prompt surgical correction.', 'Obstetric & Neonatal', '🤱', true),
(3266, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'Croup in a child is classically characterised by:', '["A high-pitched, barking cough with inspiratory stridor", "Silent chest with no cough", "Chronic productive cough over months", "Painless swallowing difficulty"]'::jsonb, 0, 'Croup (laryngotracheobronchitis) classically causes a barking cough and inspiratory stridor due to upper airway inflammation and narrowing.', 'Obstetric & Neonatal', '🤱', true),
(3267, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'Epiglottitis in a child is a medical emergency mainly because of the risk of:', '["Mild sore throat only", "Rapid, complete airway obstruction", "Chronic hoarseness", "Ear infection"]'::jsonb, 1, 'Epiglottitis causes rapid swelling that can completely obstruct the airway, making it a critical emergency requiring careful, minimal-intervention airway management.', 'Obstetric & Neonatal', '🤱', true),
(3268, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'A child presenting with epiglottitis should generally be managed by:', '["Immediately examining the throat with a tongue depressor", "Avoiding upsetting/examining the throat unnecessarily and urgently involving anaesthesia/ENT for controlled airway management", "Sending the child home with oral antibiotics", "Encouraging the child to lie flat immediately"]'::jsonb, 1, 'Throat examination or upsetting a child with suspected epiglottitis can precipitate complete airway obstruction — urgent, controlled airway management by experienced teams is essential.', 'Obstetric & Neonatal', '🤱', true),
(3269, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'Sudden Infant Death Syndrome (SIDS) risk is reduced by which key recommendation?', '["Placing infants to sleep prone (on their stomach)", "Placing infants to sleep supine (on their back)", "Co-sleeping in the same bed as an adult at all times", "Using soft, loose bedding in the crib"]'::jsonb, 1, 'The ''back to sleep'' recommendation — placing infants supine — is a key evidence-based measure shown to reduce SIDS risk.', 'Obstetric & Neonatal', '🤱', true),
(3270, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'Neonatal sepsis should be suspected in a newborn presenting with:', '["Only a normal temperature with no other findings", "Non-specific signs such as poor feeding, temperature instability, lethargy, or respiratory distress", "Only visible jaundice, with no other clue needed", "Normal activity and feeding with no concerning signs"]'::jsonb, 1, 'Neonatal sepsis often presents with non-specific signs — poor feeding, temperature instability, lethargy or respiratory distress — requiring a high index of suspicion.', 'Obstetric & Neonatal', '🤱', true),
(3271, 'Paediatric Medical Emergencies (CCN 422)', 'AI Practice Question', 'Severe neonatal jaundice is primarily concerning because untreated high bilirubin levels can cause:', '["No lasting harm regardless of level", "Kernicterus (bilirubin-induced brain damage)", "Improved neurological development", "Only mild, temporary skin discolouration with no other risk"]'::jsonb, 1, 'Untreated severe hyperbilirubinaemia can cross the blood-brain barrier and cause kernicterus, a form of permanent brain damage — hence the urgency of treatment (phototherapy/exchange transfusion).', 'Obstetric & Neonatal', '🤱', true),
(3272, 'Paediatric Fluid & Dehydration (CCN 422)', 'AI Practice Question', 'Assessing dehydration severity in a paediatric patient includes evaluating all of the following EXCEPT:', '["Skin turgor", "Mucous membrane moisture", "Urine output", "The child''s favourite toy"]'::jsonb, 3, 'Skin turgor, mucous membrane moisture, and urine output are all clinical indicators of hydration status; a child''s toy preference is irrelevant.', 'Obstetric & Neonatal', '🤱', true),
(3273, 'Paediatric Fluid & Dehydration (CCN 422)', 'AI Practice Question', 'Fluid therapy in a severely dehydrated child typically begins with:', '["Oral fluids only, regardless of severity", "A rapid IV fluid bolus for severe dehydration, followed by ongoing maintenance and deficit replacement", "Withholding all fluids until specialist review", "Only subcutaneous fluids"]'::jsonb, 1, 'Severe paediatric dehydration is managed with an initial rapid IV fluid bolus to restore circulating volume, followed by calculated maintenance and deficit replacement.', 'Obstetric & Neonatal', '🤱', true),
(3274, 'Paediatric Haematology (CCN 422)', 'AI Practice Question', 'Sickle cell crisis in a child is typically managed with:', '["Fluid restriction and cold application", "Hydration, analgesia, oxygen, and treatment of any precipitating factor (e.g. infection)", "Immediate blood transfusion in every case regardless of severity", "Strict bed rest with no other intervention"]'::jsonb, 1, 'Sickle cell crisis management centres on hydration, effective analgesia, oxygen therapy, and treating any underlying trigger such as infection.', 'Obstetric & Neonatal', '🤱', true),
(3275, 'Paediatric Haematology (CCN 422)', 'AI Practice Question', 'Childhood leukaemia is best broadly described as:', '["A localised bone infection", "A malignancy of white blood cell precursors, disrupting normal blood cell production", "A disorder limited to red blood cells", "A benign, self-limiting skin condition"]'::jsonb, 1, 'Leukaemia is a haematological malignancy arising from abnormal proliferation of white blood cell precursors, which can crowd out normal blood cell production.', 'Obstetric & Neonatal', '🤱', true),
(3276, 'Paediatric Emergencies (CCN 422)', 'AI Practice Question', 'Febrile convulsions in young children are most commonly associated with:', '["A rapid rise in body temperature, often with a viral infection", "Chronic malnutrition alone", "Congenital heart disease exclusively", "Vitamin overdose"]'::jsonb, 0, 'Febrile convulsions typically occur with a rapid temperature rise in young children, often triggered by a common viral illness.', 'Obstetric & Neonatal', '🤱', true),
(3277, 'Radiology (CCN 427)', 'AI Practice Question', 'IVP (Intravenous Pyelogram), like IVU, is used to assess which organ system, distinguished mainly by its focus on:', '["The respiratory system", "The urinary collecting system (renal pelvis, ureters) using excreted contrast", "The gastrointestinal tract", "The cardiovascular system"]'::jsonb, 1, 'IVP/IVU both use IV contrast excreted by the kidneys to visualise the urinary collecting system, showing structure and function of the kidneys, ureters and bladder.', 'Radiology & Imaging', '🩻', true),
(3278, 'Radiology (CCN 427)', 'AI Practice Question', 'Basic radiological principles in the critically ill patient include selecting the imaging type based primarily on:', '["Whichever machine is nearest, regardless of clinical question", "The clinical indication and the specific diagnostic question being asked", "Patient preference alone", "Cost only, with no regard to diagnostic yield"]'::jsonb, 1, 'Choice of imaging modality (X-ray, CT, ultrasound, MRI) should be guided by the clinical indication and what diagnostic information is actually needed.', 'Radiology & Imaging', '🩻', true),
(3279, 'Radiology (CCN 427)', 'AI Practice Question', 'On imaging of intestinal obstruction, distinguishing small bowel from large bowel obstruction is aided by which feature?', '["Small bowel loops show valvulae conniventes (complete transverse lines); large bowel shows haustra (incomplete lines)", "There is no radiological way to distinguish them", "Only CT can ever differentiate them, never plain X-ray", "Large bowel is always more centrally located regardless of distension"]'::jsonb, 0, 'Valvulae conniventes crossing the full width of small bowel loops versus the partial haustral markings of large bowel are classic plain-film differentiators.', 'Radiology & Imaging', '🩻', true),
(3280, 'Nursing Informatics & ICT', 'AI Practice Question', 'An example of a ''transition programme'' type of software mentioned in nursing informatics refers to software used to:', '["Permanently delete all system data", "Convert or migrate data between different systems/formats", "Only play multimedia files", "Control physical building access"]'::jsonb, 1, 'Transition/conversion programmes facilitate migrating or converting data between different software systems or formats, important when hospitals change information systems.', 'Nursing Informatics & ICT', '💻', true),
(3281, 'Nursing Informatics & ICT', 'AI Practice Question', 'Internet-based email communication in a healthcare setting requires particular attention to:', '["No special precautions, since email is always secure", "Patient confidentiality and secure transmission of any identifiable health information", "Only the sender''s typing speed", "Avoiding all professional communication"]'::jsonb, 1, 'Any electronic communication containing identifiable patient information must be handled securely to protect confidentiality, in line with data protection obligations.', 'Nursing Informatics & ICT', '💻', true),
(3282, 'Nursing Informatics & ICT', 'AI Practice Question', 'Random access file arrangement, compared to sequential access, allows:', '["Records to be accessed directly without reading through all preceding records", "Only reading records strictly in the order they were stored", "No possibility of updating individual records", "Access only during scheduled batch windows"]'::jsonb, 0, 'Random access allows direct retrieval of a specific record without sequentially reading through all prior records, unlike strictly sequential access.', 'Nursing Informatics & ICT', '💻', true),
(3283, 'Nursing Informatics & ICT', 'AI Practice Question', 'Multi-processing in a computer file system refers to the ability to:', '["Process only one task at a time, strictly in sequence", "Handle multiple processing tasks concurrently", "Never process data outside business hours", "Only work with a single connected device"]'::jsonb, 1, 'Multi-processing capability allows a system to handle several processing tasks concurrently, improving efficiency for multi-user hospital systems.', 'Nursing Informatics & ICT', '💻', true),
(3284, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Biochemical laboratory investigations in critical care commonly include measurement of:', '["Electrolytes, renal and liver function tests", "Only bone density", "Only visual acuity", "Only hearing thresholds"]'::jsonb, 0, 'Biochemical investigations commonly assess electrolytes, renal function (urea/creatinine) and liver function — key parameters for monitoring critically ill patients.', 'Laboratory Sciences & Haematology', '🔬', true),
(3285, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Haematological investigations typically assess:', '["Blood cell counts, haemoglobin, and coagulation parameters", "Only urine composition", "Only stool consistency", "Only skin pigmentation"]'::jsonb, 0, 'Haematological tests evaluate blood cell counts (red cells, white cells, platelets), haemoglobin, and coagulation status.', 'Laboratory Sciences & Haematology', '🔬', true),
(3286, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'A key clinical clue distinguishing DIC from an isolated bleeding disorder is that DIC involves:', '["Bleeding only, with normal clotting elsewhere in the body", "Simultaneous bleeding AND widespread microvascular clotting, consuming platelets and clotting factors", "Clotting only, with no bleeding risk whatsoever", "A condition confined strictly to the skin"]'::jsonb, 1, 'DIC''s hallmark is the paradoxical combination of widespread clotting (consuming platelets/factors) and resulting bleeding, unlike an isolated bleeding disorder.', 'Laboratory Sciences & Haematology', '🔬', true),
(3287, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Disinfection, as distinct from sterilisation, is best described as a process that:', '["Destroys all microorganisms including bacterial spores", "Reduces the number of pathogenic microorganisms but may not eliminate all spores", "Is only used for surgical instruments", "Requires no equipment at all"]'::jsonb, 1, 'Disinfection reduces pathogens to a safe level but does not reliably eliminate all bacterial spores, unlike sterilisation which destroys everything including spores.', 'Laboratory Sciences & Haematology', '🔬', true),
(3288, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Blood transfusion reactions can be classified broadly as:', '["Only immediate reactions exist; delayed reactions are not possible", "Immediate (e.g. acute haemolytic, allergic) and delayed (e.g. delayed haemolytic, iron overload) reactions", "Only allergic reactions occur", "Reactions cannot be classified in any meaningful way"]'::jsonb, 1, 'Transfusion reactions are classified into immediate reactions (occurring during/shortly after transfusion) and delayed reactions (occurring days to weeks later).', 'Laboratory Sciences & Haematology', '🔬', true),
(3289, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Diagnostic peritoneal lavage is a procedure used in trauma primarily to detect:', '["Pneumothorax", "Intra-abdominal haemorrhage/injury", "Fractures of the long bones", "Skull fractures"]'::jsonb, 1, 'Diagnostic peritoneal lavage is used to detect intra-abdominal bleeding or injury in trauma patients, particularly when other imaging is unavailable or inconclusive.', 'Disaster & Emergency Nursing', '🚨', true),
(3290, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Underwater seal chest drainage is used to manage which condition?', '["Urinary retention", "Pneumothorax or haemothorax, by draining air/fluid from the pleural space", "Constipation", "Gastric distension"]'::jsonb, 1, 'Underwater seal chest drainage allows air/fluid to exit the pleural space while preventing air from re-entering, used to manage pneumothorax or haemothorax.', 'Disaster & Emergency Nursing', '🚨', true),
(3291, 'Disaster & Emergency Nursing', 'AI Practice Question', 'A key nursing responsibility when managing a patient with an underwater seal chest drain is to:', '["Keep the drainage bottle above the level of the chest at all times", "Keep the drainage bottle below the level of the chest, and observe for fluctuation (''swing'') and bubbling", "Clamp the tube continuously to prevent any drainage", "Disconnect the tube whenever the patient wants to move"]'::jsonb, 1, 'The bottle must stay below chest level to allow gravity drainage and prevent fluid siphoning back into the pleural space; swing and bubbling are monitored to assess drain function.', 'Disaster & Emergency Nursing', '🚨', true),
(3292, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Necrotising fasciitis is best described as:', '["A mild, self-limiting skin rash", "A rapidly progressive, life-threatening soft tissue infection destroying fascia and subcutaneous tissue", "A chronic, slow-growing skin condition", "A purely cosmetic skin concern"]'::jsonb, 1, 'Necrotising fasciitis is a rapidly progressive, life-threatening infection that destroys fascia and soft tissue, requiring urgent surgical debridement alongside antibiotics.', 'Disaster & Emergency Nursing', '🚨', true),
(3293, 'Disaster & Emergency Nursing', 'AI Practice Question', 'A hallmark early clinical clue suggesting necrotising fasciitis, distinguishing it from simple cellulitis, is:', '["Pain out of proportion to visible skin findings", "Mild, well-localised redness with minimal pain", "Slow onset over several weeks", "Complete absence of systemic symptoms"]'::jsonb, 0, 'Pain disproportionate to the apparent severity of skin findings is a classic early warning sign of necrotising fasciitis, prompting urgent surgical evaluation.', 'Disaster & Emergency Nursing', '🚨', true),
(3294, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Blunt aortic trauma management priorities include:', '["Allowing blood pressure to rise as high as possible to maintain perfusion", "Careful blood pressure and heart rate control to reduce shear stress on the injured aorta, alongside urgent imaging", "Immediate discharge if the patient feels well", "No blood pressure monitoring is needed"]'::jsonb, 1, 'Blunt aortic injury management focuses on controlling blood pressure/heart rate to minimise shear stress on the damaged aortic wall, alongside urgent diagnostic imaging and surgical planning.', 'Disaster & Emergency Nursing', '🚨', true),
(3295, 'Disaster & Emergency Nursing', 'AI Practice Question', 'An intra-ventricular pressure monitor is used to measure:', '["Cardiac output only", "Intracranial pressure via a catheter placed in the brain''s ventricular system", "Blood glucose", "Peripheral oxygen saturation"]'::jsonb, 1, 'An intraventricular catheter directly measures intracranial pressure, providing precise ICP monitoring in patients with severe brain injury.', 'Disaster & Emergency Nursing', '🚨', true),
(3296, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The Nursing and Midwifery Council of Nigeria (NMCN), as a professional regulatory body, is primarily responsible for:', '["Setting nursing education standards, registering/licensing nurses, and enforcing professional discipline", "Only organising nursing conferences", "Managing hospital construction budgets", "Setting national drug prices"]'::jsonb, 0, 'NMCN''s core functions include setting education/practice standards, registering and licensing nurses/midwives, and handling matters of professional discipline.', 'Ethics, Law & Management', '⚖️', true),
(3297, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'International nursing organisations (e.g. the International Council of Nurses) primarily contribute to the profession by:', '["Setting local hospital staffing schedules directly", "Promoting global nursing standards, advocacy, and professional development", "Replacing the need for any national regulatory body", "Having no real influence on national nursing practice"]'::jsonb, 1, 'International bodies like the ICN promote global standards, advocacy for the profession, and professional development, complementing (not replacing) national regulators.', 'Ethics, Law & Management', '⚖️', true),
(3298, 'Management & Teaching (GST 420)', 'AI Practice Question', 'A nurse manager reviewing a department''s risk management programme should ensure it includes:', '["Common risk categories, elements of risk management, and a functioning incident reporting system", "Only a list of staff names", "No formal documentation, to save time", "A focus solely on financial risk, excluding patient safety risk"]'::jsonb, 0, 'An effective departmental risk management programme addresses relevant risk categories, applies core risk management elements, and relies on functioning incident reporting.', 'Ethics, Law & Management', '⚖️', true),
(3299, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Hypnotic medications differ from anxiolytics primarily in their main clinical purpose, which is to:', '["Reduce anxiety during waking hours specifically", "Induce and maintain sleep", "Treat bacterial infections", "Lower blood pressure"]'::jsonb, 1, 'While some drug classes overlap, hypnotics are specifically used to induce/maintain sleep, distinct from anxiolytics'' primary anti-anxiety purpose.', 'ICU Pharmacology', '💊', true),
(3300, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Drug overdose management in the critical care unit generally follows which sequence of priorities?', '["Airway/breathing/circulation support first, then specific decontamination/antidote measures where appropriate", "Antidote administration only, with no attention to airway/breathing/circulation", "Discharge planning first, before any stabilisation", "Ignoring vital signs until toxicology results return"]'::jsonb, 0, 'Overdose management always prioritises ABC stabilisation first, followed by specific decontamination (e.g. activated charcoal) or antidote administration where indicated.', 'ICU Pharmacology', '💊', true),
(3301, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Poisoning management in the ICU may include gastric lavage, which is most effective when performed:', '["More than 24 hours after ingestion", "Within about 1 hour of ingestion (up to 2–4 hours in some cases), and never in corrosive poisoning", "At any time regardless of the substance ingested", "Only in infants"]'::jsonb, 0, 'Gastric lavage is most useful shortly after ingestion (roughly within 1–4 hours) and is contraindicated in corrosive/caustic poisoning due to perforation risk.', 'ICU Pharmacology', '💊', true)
